\n        ON f.id = a.facility_id\n    WHERE c.expiry_date IS NOT NULL\n      AND c.expiry_date <= DATE_ADD(CURDATE(), INTERVAL 120 DAY)\n      AND a.facility_id = 14\n\n    UNION ALL\n\n    SELECT\n        'Uploaded Document' AS source,\n        COALESCE(f.name, 'Unassigned') AS facility_name,\n        COALESCE(u.employee_num, e.employee_num) AS employee_num,\n        TRIM(CONCAT(COALESCE(e.last_name, ''), IF(e.last_name IS NULL OR e.first_name IS NULL, '', ', '), COALESCE(e.first_name, ''), IF(COALESCE(e.middle_name, '') = '', '', CONCAT(' ', e.middle_name)))) AS employee_name,\n        COALESCE(ut.name, ci.name, u.original_filename) AS document_name,\n        NULL AS credential_number,\n        NULL AS issuing_authority,\n        u.effective_start_date AS issue_date,\n        u.expires_at AS expiration_date,\n        DATEDIFF(u.expires_at, CURDATE()) AS days_until_expiration,\n        CASE\n            WHEN u.expires_at < CURDATE() THEN 'Expired'\n            WHEN u.expires_at = CURDATE() THEN 'Expires today'\n            WHEN u.expires_at <= DATE_ADD(CURDATE(), INTERVAL 30 DAY) THEN 'Expiring in 30 days'\n            WHEN u.expires_at <= DATE_ADD(CURDATE(), INTERVAL 60 DAY) THEN 'Expiring in 60 days'\n            ELSE 'Expiring in 120 days'\n        END AS expiration_status,\n        COALESCE(u.verification_status, 'not submitted') AS verification_status\n    FROM uploads u\n    LEFT JOIN upload_types ut\n        ON ut.id = u.upload_type_id\n    LEFT JOIN checklist_items ci\n        ON ci.id = u.checklist_item_id\n    LEFT JOIN bp_employees e\n        ON e.employee_num = u.employee_num\n    LEFT JOIN facilities f\n        ON f.id = u.facility_id\n    WHERE u.expires_at IS NOT NULL\n      AND u.expires_at <= DATE_ADD(CURDATE(), INTERVAL 120 DAY)\n      AND u.facility_id = 14\n      AND (\n          ut.is_license_or_certification = 1\n          OR ci.is_license_or_certification = 1\n      )\n) expiring_items\nORDER BY expiration_date ASC, facility_name ASC, employee_name ASC, document_name ASC",
